import AxiosAuthInstance from "@/lib/axios-auth";

// Simplified HTTP client — direct method calls
export const api = {
  get:      (url: string) => AxiosAuthInstance.get(url),
  post:     <T = unknown>(url: string, data?: T) => AxiosAuthInstance.post(url, data),
  postForm: (url: string, data: FormData) => AxiosAuthInstance.post(url, data, {
    headers: { 'Content-Type': 'multipart/form-data', 'Content-Length': 'Infinity' }
  }),
  put:      <T = unknown>(url: string, data?: T) => AxiosAuthInstance.put(url, data),
  patch:    <T = unknown>(url: string, data?: T) => AxiosAuthInstance.patch(url, data),
  delete:   (url: string) => AxiosAuthInstance.delete(url),
};

// Backward-compatible exports (deprecated — use api.* directly)
export enum HttpMethod {
    GET = 'get',
    POST = 'post',
    POST_FORM = 'post_form',
    PUT = 'put',
    PATCH = 'patch',
    DELETE = 'delete'
}

export const createApiCall = async <T = unknown>(method: HttpMethod, endpoint: string, payload?: T) => {
    switch (method) {
        case HttpMethod.GET:       return api.get(endpoint);
        case HttpMethod.POST:      return api.post(endpoint, payload);
        case HttpMethod.POST_FORM: return api.postForm(endpoint, payload as unknown as FormData);
        case HttpMethod.PUT:       return api.put(endpoint, payload);
        case HttpMethod.PATCH:     return api.patch(endpoint, payload);
        case HttpMethod.DELETE:    return api.delete(endpoint);
        default: throw new Error(`Unsupported method: ${method}`);
    }
};

