import { createApiCall, HttpMethod } from "./api";
import { SearchEndPoints } from "@/constants/ApiConstants";

const generic = (status: number, fallback: string): string => {
    switch (status) {
        case 0: return 'No internet connection. Please check your network and try again.';
        case 401: return 'Your session has expired. Please login again to search.';
        case 403: return 'Access denied. You do not have permission to search.';
        case 429: return 'You are searching too frequently. Please wait a moment.';
        case 500: return 'Something went wrong on our end. Please try again later.';
        default: return fallback;
    }
};

export const SearchServicesError = {
    UnifiedSearchError: (s: number) => generic(s, 'Search failed. Please try again.'),
};

// Search endpoints return the payload directly (no OpResult envelope on the backend).
// The axios interceptor passes them through unchanged.
export const SearchServices = {
    // Authenticated: Unified search across profiles and businesses. Supports text query, geo filters, school/batch filters.
    UnifiedSearch:      async (query: string, pagination?: { pageNumber?: number; pageSize?: number; schoolName?: string; entryYear?: number; exitYear?: number; lat?: number; lng?: number; radiusKm?: number }) =>
        createApiCall(HttpMethod.GET, SearchEndPoints.UnifiedSearch(query, pagination?.pageNumber, pagination?.pageSize, pagination?.schoolName, pagination?.entryYear, pagination?.exitYear, pagination?.lat, pagination?.lng, pagination?.radiusKm)),
    // Admin: rebuild the profile search index.
    IndexProfiles:      async () => createApiCall(HttpMethod.POST, SearchEndPoints.IndexProfiles()),
    // Admin: rebuild the business search index.
    IndexBusinesses:    async () => createApiCall(HttpMethod.POST, SearchEndPoints.IndexBusinesses()),
};
