import React, { useEffect, useState } from "react";
import { Box, Button, IconButton, Typography, useMediaQuery, useTheme } from "@mui/material";
import WhatsAppIcon from "@mui/icons-material/WhatsApp";
import CloseIcon from "@mui/icons-material/Close";
import { ProfileServices } from "@/api";
import { getWhatsAppGroup, openWhatsAppGroup, WhatsAppGroupConfig } from "@/constants/StaticData";

export const WA_BANNER_DISMISSED_KEY = 'wa_banner_dismissed';

export const WhatsAppBanner: React.FC = () => {
  const [waGroup, setWaGroup] = useState<WhatsAppGroupConfig | undefined>();
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('sm'), { noSsr: true });

  const handleJoin = () => { if (waGroup) openWhatsAppGroup(waGroup); };

  useEffect(() => {
    if (localStorage.getItem(WA_BANNER_DISMISSED_KEY) === '1') return;
    let cancelled = false;
    (async () => {
      try {
        const res = await ProfileServices.GetProfile();
        if (cancelled) return;
        const profile = res?.data?.result;
        if (!profile) return;
        const group = getWhatsAppGroup(profile.firstJnvId, profile.location);
        setWaGroup(group);
      } catch { /* ignore */ }
    })();
    return () => { cancelled = true; };
  }, []);

  if (!waGroup || !isMobile) return null;

  return (
    <Box sx={{
      backgroundColor: '#dcf8c6',
      borderRadius: 2,
      p: 2,
      pb: 3.5,
      mb: 2,
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'space-between',
      flexWrap: 'wrap',
      gap: 1,
      position: 'relative',
    }}>
      <Typography variant="body2" sx={{ color: 'text.primary', fontWeight: 500, flexGrow: 1 }}>
        Join the <b style={{ color: '#d32f2f' }}>{waGroup.label}</b> WhatsApp Group!
      </Typography>
      <Button
        variant="contained"
        size="small"
        startIcon={<WhatsAppIcon />}
        onClick={handleJoin}
        sx={{
          backgroundColor: '#25D366',
          '&:hover': { backgroundColor: '#1ebe57' },
          textTransform: 'none',
          fontWeight: 600,
        }}
      >
        Join Group
      </Button>
      <IconButton
        size="small"
        onClick={() => {
          localStorage.setItem(WA_BANNER_DISMISSED_KEY, '1');
          setWaGroup(undefined);
        }}
        sx={{ position: 'absolute', right: 4, bottom: 4, color: 'text.secondary' }}
      >
        <CloseIcon sx={{ fontSize: '1.1rem' }} />
      </IconButton>
    </Box>
  );
};
