import { createApiCall, HttpMethod } from "./api";
import { ProfileEndPoints, SearchEndPoints } from "@/constants/ApiConstants";
import { CreateProfilePayload, UpdateProfilePayload, ProfileGeoUpdatePayload, AdvancedSearchProfilePayload } from "@/types/profile.types";
import { PaginationRequest, Roles } from "@/types/api.types";
import { IsAdminUser } from "@/utils/token";

const generic = (status: number, fallback: string): string => {
    switch (status) {
        case 0: return 'Network error. Please check your internet connection.';
        case 400: return 'Invalid request. Please check your input.';
        case 401: return 'Unauthorized. Please login again.';
        case 403: return 'Access denied. You do not have permission for this action.';
        case 404: return 'Not found.';
        case 409: return 'Conflict. The resource already exists.';
        case 429: return 'Too many requests. Please wait a moment.';
        case 500: return 'Server error. Please try again later.';
        default: return fallback;
    }
};

export const ProfileServicesError = {
    CreateProfileError:        (s: number) => generic(s, 'Failed to create profile. Please try again.'),
    UpdateProfileError:        (s: number) => generic(s, 'Failed to update profile. Please try again.'),
    GetProfileError:           (s: number) => generic(s, 'Failed to load profile. Please try again.'),
    GetBatchmatesError:        (s: number) => generic(s, 'Failed to load batchmates. Please try again.'),
    GetProfilesByPhoneError:   (s: number) => generic(s, 'Failed to search profiles by phone. Please try again.'),
    GetProfileByIdError:       (s: number) => generic(s, 'Failed to load profile. Please try again.'),
    SearchProfileError:        (s: number) => generic(s, 'Search failed. Please try again.'),
};

export const ProfileServices = {
    // Authenticated: Fetch the current user's full profile (private view with lat/lon, roles).
    GetProfile:                  async () => createApiCall(HttpMethod.GET, ProfileEndPoints.GetMyProfile()),
    // Authenticated: Alias for GetProfile — both hit GET /profile/me.
    GetMyProfile:                async () => createApiCall(HttpMethod.GET, ProfileEndPoints.GetMyProfile()),
    // Authenticated: Fetch another user's public profile by their userId.
    GetProfileById:              async (id: string) => createApiCall(HttpMethod.GET, ProfileEndPoints.GetProfileById(id)),
    // Admin: fetch another user's full private profile (includes roles, geo, audit fields).
    GetAdminProfileById:         async (id: string) => createApiCall(HttpMethod.GET, ProfileEndPoints.GetAdminProfileById(id)),
    // Role-aware: returns the admin profile (full ProfileResult with roles/audit
    // fields) when the caller has Admin/SuperAdmin role, otherwise returns the
    // public view (PublicProfileResult). Use this from any UI surface that
    // doesn't know the caller's role at call site.
    GetProfileForCurrentUser:    async (id: string) => IsAdminUser()
        ? createApiCall(HttpMethod.GET, ProfileEndPoints.GetAdminProfileById(id))
        : createApiCall(HttpMethod.GET, ProfileEndPoints.GetProfileById(id)),
    // Admin: search profiles by phone number.
    GetProfileByPhone:           async (phone: string) => createApiCall(HttpMethod.GET, ProfileEndPoints.GetProfileByPhone(phone)),
    // Admin: search by phone, wrapped into a PaginatedResult envelope for list views.
    GetProfilesByPhone:          async (phone: string, _pagination?: PaginationRequest) => {
        const res = await createApiCall(HttpMethod.GET, ProfileEndPoints.GetProfileByPhone(phone));
        if (res.data?.result && Array.isArray(res.data.result)) {
            res.data = { ...res.data, result: { items: res.data.result, hasNextPage: false, continuationToken: null } };
        }
        return res;
    },
    // Authenticated: Create a new profile for the current user (first-time registration).
    CreateProfile:               async (payload: CreateProfilePayload) => createApiCall(HttpMethod.POST, ProfileEndPoints.PostProfile(), payload),
    // Authenticated: Update the current user's own profile (JSON Merge Patch — partial fields).
    UpdateProfile:               async (payload: UpdateProfilePayload) => createApiCall(HttpMethod.PATCH, ProfileEndPoints.PatchMyProfile(), payload),
    // Authenticated: Upload or replace the current user's profile photo.
    UpdateProfilePhoto:          async (payload: FormData)             => createApiCall(HttpMethod.POST_FORM, ProfileEndPoints.PostMyPhoto(), payload),
    // Authenticated: Update the current user's geolocation (latitude/longitude) for nearby search.
    UpdateProfileGeo:            async (payload: ProfileGeoUpdatePayload) => createApiCall(HttpMethod.PUT, ProfileEndPoints.PutMyGeo(), payload),
    // SuperAdmin: assign roles to a user by their userId.
    UpdateUserRoles:             async (userId: string, roles: Roles[] | string[]) =>
        createApiCall(HttpMethod.PUT, ProfileEndPoints.UpdateUserRoles(userId), { roles }),
    // Admin: list all profiles with non-User roles (elevated roles list).
    GetProfilesWithElevatedRoles:async (paginationRequest?: PaginationRequest) =>
        createApiCall(HttpMethod.GET, ProfileEndPoints.GetProfilesWithElevatedRoles(paginationRequest)),
    // EventMgr/Admin: typeahead search of users with elevated roles (for event owner/manager picker).
    // Empty `q` returns the first `take` elevated users alphabetically.
    SearchElevatedProfiles:      async (q?: string, take: number = 20) =>
        createApiCall(HttpMethod.GET, ProfileEndPoints.SearchElevatedProfiles(q, take)),
    // Admin: list all suspended profiles (no roles).
    GetSuspendedProfiles:        async (paginationRequest?: PaginationRequest) =>
        createApiCall(HttpMethod.GET, ProfileEndPoints.GetSuspendedProfiles(paginationRequest)),
    // Admin: permanently delete another user's profile.
    DeleteProfileAdmin:          async (id: string) => createApiCall(HttpMethod.DELETE, ProfileEndPoints.DeleteAdminProfile(id)),
    // Admin: update another user's profile fields.
    UpdateProfileAdmin:          async (id: string, payload: UpdateProfilePayload) =>
        createApiCall(HttpMethod.PATCH, ProfileEndPoints.PatchAdminProfile(id), payload),
    // Authenticated: Search profiles via the unified search index (text query + pagination).
    SearchProfile:               async (query: string, pagination?: { pageNumber?: number; pageSize?: number; continuationToken?: string }) =>
        createApiCall(HttpMethod.GET, SearchEndPoints.UnifiedSearch(query, pagination?.pageNumber, pagination?.pageSize)),
    // Authenticated: Advanced field-specific search (name, location, organisation, etc.) via the unified search index.
    AdvancedSearchProfile:       async (payload: AdvancedSearchProfilePayload) => {
        // Map advanced field search to the unified /search endpoint using query params
        const searchText = payload.name || payload.location || payload.organisation ||
            payload.jobTitle || payload.university || payload.degree ||
            payload.phone || payload.email || '';
        return createApiCall(HttpMethod.GET, SearchEndPoints.UnifiedSearch(
            searchText,
            payload.pageNumber,
            payload.pageSize,
            payload.schoolName,
            payload.entryYear,
            payload.exitYear,
        ));
    },
};

