import { createApiCall, HttpMethod } from "./api";
import { AuthEndPoints } from "@/constants/ApiConstants";
import { AdaptTokenResponse, CreateOtpPayload, CreateTokenPayload, TokenResponse } from "@/types/auth.types";

const generic = (status: number, fallback: string): string => {
    switch (status) {
        case 0: return 'Network error. Please check your internet connection and try again.';
        case 400: return 'Invalid request. Please check your input.';
        case 401: return 'Unauthorized. Please login again.';
        case 403: return 'Access denied. Please contact support.';
        case 429: return 'Too many requests. Please wait a moment.';
        case 500: return 'Server error. Please try again later.';
        default: return fallback;
    }
};

export const AuthServicesError = {
    CreateOtpError:   (status: number) => generic(status, 'Failed to send OTP. Please try again.'),
    CreateTokenError: (status: number) => status === 401
        ? 'Incorrect login credentials. Please check your email and OTP and try again.'
        : status === 403
        ? 'Your account has been suspended. Please contact an admin to restore access.'
        : generic(status, 'Login failed. Please try again.'),
    RefreshTokenError:(status: number) => generic(status, 'Failed to refresh session. Please try again.'),
    ResetAuthError:   (status: number) => generic(status, 'Failed to reset authentication. Please try again.'),
    GetTotpSetupError:(status: number) => generic(status, 'Failed to load authenticator setup. Please try again.'),
    AdminUnlockOtpError:(status: number) => generic(status, 'Failed to clear the OTP lockout. Please try again.'),
};

export const AuthServices = {
    // Public: Send a one-time password to the user's email/phone. Called from the Login page.
    CreateOtp:   async (payload: CreateOtpPayload)   => createApiCall(HttpMethod.POST, AuthEndPoints.PostAuthOtp(),   payload),
    // Public: Exchange email+OTP for a JWT. Adapts the new TokenResponse to the legacy AuthTokenResult shape.
    // expected by SetAccessTokenData / consumers (xv, accessToken, name, resource, …).
    CreateToken: async (payload: CreateTokenPayload) => {
        const response = await createApiCall(HttpMethod.POST, AuthEndPoints.PostAuthToken(), payload);
        const envelope = response.data as { status: number; errorCode: number; result?: TokenResponse; error?: string };
        if (envelope?.result && envelope.status >= 200 && envelope.status < 300) {
            response.data = { ...envelope, result: AdaptTokenResponse(envelope.result) };
        }
        return response;
    },
    // Authenticated: Re-issues a JWT for the current user with up-to-date claims (roles, profile complete flag).
    RefreshToken: async () => {
        const response = await createApiCall(HttpMethod.POST, AuthEndPoints.PostAuthRefresh());
        const envelope = response.data as { status: number; errorCode: number; result?: TokenResponse; error?: string };
        if (envelope?.result && envelope.status >= 200 && envelope.status < 300) {
            response.data = { ...envelope, result: AdaptTokenResponse(envelope.result) };
        }
        return response;
    },
    // Authenticated: Reset for the current user — no payload needed.
    ResetMine:   async ()                             => createApiCall(HttpMethod.POST, AuthEndPoints.PostAuthResetMine()),
    // Admin-only: rotates the security key for the target profile, forcing logout from all devices.
    AdminReset:  async (profileId: string)            => createApiCall(HttpMethod.POST, AuthEndPoints.PostAdminAuthReset(profileId)),
    // Authenticated: Returns TOTP provisioning data (base32 secret + otpauth:// URI + account/issuer)
    // for setting up Google / Microsoft Authenticator (and other RFC 6238 TOTP apps).
    GetTotpSetup:async ()                             => createApiCall(HttpMethod.GET,  AuthEndPoints.GetAuthTotpSetup()),
    // Admin-only (SuperAdmin): generate an OTP on behalf of another user.
    AdminGenerateOtp: async (payload: { email: string; otp?: string }) =>
        createApiCall(HttpMethod.POST, AuthEndPoints.PostAdminOtp(), { emailOrPhone: payload.email }),
    // Admin-only: clears any active OTP lockout on the given identifier so the user can log in again.
    AdminUnlockOtp: async (emailOrPhone: string) =>
        createApiCall(HttpMethod.POST, AuthEndPoints.PostAdminAuthUnlock(), { emailOrPhone }),
};
