// Get Schools.json as SchoolData[]

import { SchoolData } from "../types/api.types";

import SchoolsJson from './Schools.json';

export const Schools: SchoolData[] = SchoolsJson;

export interface WhatsAppGroupConfig {
  jnvId: number;
  label: string;
  locationKeywords: string[];
  link: string;
}

/**
 * Add entries here to enable WhatsApp group links for more schools.
 */
const whatsAppGroups: WhatsAppGroupConfig[] = [
  {
    jnvId: 6051556,
    label: 'JNV Sitamarhi Alumni',
    locationKeywords: ['sitamarhi'],
    link: 'https://chat.whatsapp.com/DJVJb0yngXE8n6fFatvs61',
  },
  // Add more schools here:
  // { jnvId: 1234567, label: 'JNV XYZ Alumni', locationKeywords: ['xyz'], link: 'https://chat.whatsapp.com/...' },
];

export function getWhatsAppGroup(jnvId: number, location?: string): WhatsAppGroupConfig | undefined {
  return whatsAppGroups.find(g =>
    g.jnvId === jnvId ||
    g.locationKeywords.some(kw => (location ?? '').toLowerCase().includes(kw))
  );
}

export function openWhatsAppGroup(group: WhatsAppGroupConfig): void {
  window.open(group.link, '_blank');
}
